import numpy as np
import random

# Problem Data
SMALL_KEG_CAP = 40
LARGE_KEG_CAP = 100
MAX_SMALL = 30
MAX_LARGE = 10
MAX_TOTAL = 25
MIN_LARGE = 5

# Genetic Algorithm is chosen because this is a combinatorial integer programming problem
# with two integer variables and multiple constraints. GA is well-suited for discrete and
# combinatorial optimization, especially when the search space is not too large.

# --- Genetic Algorithm Parameters ---
POP_SIZE = 60       # Population size
N_GENERATIONS = 60  # Number of generations
CX_PROB = 0.9       # Crossover probability
MUT_PROB = 0.3      # Mutation probability
TOURN_SIZE = 3      # Tournament selection size

# --- Representation: Each individual is (x, y) for small and large kegs ---

def objective(x, y):
    return SMALL_KEG_CAP * x + LARGE_KEG_CAP * y

def is_feasible(x, y):
    # All constraints
    if not (0 <= x <= MAX_SMALL):
        return False
    if not (0 <= y <= MAX_LARGE):
        return False
    if x + y > MAX_TOTAL:
        return False
    if y < MIN_LARGE:
        return False
    if x < 2 * y:
        return False
    return True

def penalty(x, y):
    # Sum of constraint violations, scaled
    pen = 0
    if x < 0:
        pen += -x * 1e5
    if x > MAX_SMALL:
        pen += (x - MAX_SMALL) * 1e5
    if y < 0:
        pen += -y * 1e5
    if y > MAX_LARGE:
        pen += (y - MAX_LARGE) * 1e5
    if x + y > MAX_TOTAL:
        pen += (x + y - MAX_TOTAL) * 1e5
    if y < MIN_LARGE:
        pen += (MIN_LARGE - y) * 1e5
    if x < 2 * y:
        pen += (2 * y - x) * 1e5
    return pen

def fitness(x, y):
    # Penalty is subtracted (for maximization)
    return objective(x, y) - penalty(x, y)

def random_individual():
    # Generate a random feasible individual by random y, then x >= 2y, etc.
    while True:
        y = random.randint(MIN_LARGE, min(MAX_LARGE, MAX_TOTAL))
        x_min = max(0, 2*y)
        x_max = min(MAX_SMALL, MAX_TOTAL - y)
        if x_min > x_max:
            continue
        x = random.randint(x_min, x_max)
        if is_feasible(x, y):
            return (x, y)

def mutate(ind):
    x, y = ind
    # Randomly increase or decrease x or y by 1, within bounds
    if random.random() < 0.5:
        # Mutate x
        x_new = x + random.choice([-1, 1])
        x_new = np.clip(x_new, 0, MAX_SMALL)
        # Adjust x if constraint violated
        if x_new < 2*y:
            x_new = 2*y
        if x_new + y > MAX_TOTAL:
            x_new = MAX_TOTAL - y
        x_new = int(np.clip(x_new, 0, MAX_SMALL))
        return (x_new, y)
    else:
        # Mutate y
        y_new = y + random.choice([-1, 1])
        y_new = np.clip(y_new, MIN_LARGE, MAX_LARGE)
        if x < 2*y_new:
            x = 2*y_new
        if x + y_new > MAX_TOTAL:
            x = MAX_TOTAL - y_new
            if x < 2*y_new:
                x = 2*y_new
        x = int(np.clip(x, 0, MAX_SMALL))
        y_new = int(y_new)
        return (x, y_new)

def crossover(parent1, parent2):
    # Uniform crossover
    x1, y1 = parent1
    x2, y2 = parent2
    if random.random() < 0.5:
        child1 = (x1, y2)
        child2 = (x2, y1)
    else:
        child1 = (x2, y1)
        child2 = (x1, y2)
    # If infeasible, repair by randomization
    def repair(ind):
        x, y = ind
        y = int(np.clip(y, MIN_LARGE, MAX_LARGE))
        x_min = max(0, 2*y)
        x_max = min(MAX_SMALL, MAX_TOTAL - y)
        if x < x_min or x > x_max:
            x = random.randint(x_min, x_max) if x_min <= x_max else x_min
        x = int(np.clip(x, 0, MAX_SMALL))
        return (x, y)
    return repair(child1), repair(child2)

def tournament_selection(pop, k):
    selected = random.sample(pop, k)
    best = max(selected, key=lambda ind: fitness(ind[0], ind[1]))
    return best

# --- GA Main Loop ---
random.seed(42)
np.random.seed(42)

# Initialize population
population = [random_individual() for _ in range(POP_SIZE)]

best_ind = None
best_fit = float('-inf')

for gen in range(N_GENERATIONS):
    new_population = []
    while len(new_population) < POP_SIZE:
        # Selection
        parent1 = tournament_selection(population, TOURN_SIZE)
        parent2 = tournament_selection(population, TOURN_SIZE)
        # Crossover
        if random.random() < CX_PROB:
            child1, child2 = crossover(parent1, parent2)
        else:
            child1, child2 = parent1, parent2
        # Mutation
        if random.random() < MUT_PROB:
            child1 = mutate(child1)
        if random.random() < MUT_PROB:
            child2 = mutate(child2)
        new_population.extend([child1, child2])

    # Truncate to POP_SIZE
    population = new_population[:POP_SIZE]

    # Track best
    for ind in population:
        fit = fitness(ind[0], ind[1])
        if fit > best_fit and is_feasible(ind[0], ind[1]):
            best_fit = fit
            best_ind = ind

# Output best solution
if best_ind is not None:
    x, y = best_ind
    print(f"Number of small kegs (x): {x}")
    print(f"Number of large kegs (y): {y}")
    print(f"Total water: {objective(x, y)} liters")
    print(f"OBJECTIVE_VALUE: {objective(x, y)}")
else:
    print("No feasible solution found.")

import numpy as np

# --- Problem Data ---
manual_slicer_slices_per_minute = 5
automatic_slicer_slices_per_minute = 8
manual_slicer_grease_per_minute = 3
automatic_slicer_grease_per_minute = 6
minimum_slices_per_minute = 50
maximum_grease_per_minute = 35

# Penalty coefficients for constraint violation
PENALTY_SLICES = 1000
PENALTY_GREASE = 1000
PENALTY_RATIO = 1000

# --- Solution Representation ---
# (x, y): x = manual slicers, y = automatic slicers (both non-negative integers)

def objective(x, y):
    return x + y

def constraint_slices(x, y):
    return 5*x + 8*y >= minimum_slices_per_minute

def constraint_grease(x, y):
    return 3*x + 6*y <= maximum_grease_per_minute

def constraint_ratio(x, y):
    return x < y

def constraint_nonneg(x, y):
    return x >= 0 and y >= 0

def penalty(x, y):
    # Penalty for each constraint violated
    p = 0
    if 5*x + 8*y < minimum_slices_per_minute:
        p += PENALTY_SLICES * (minimum_slices_per_minute - (5*x + 8*y))
    if 3*x + 6*y > maximum_grease_per_minute:
        p += PENALTY_GREASE * ((3*x + 6*y) - maximum_grease_per_minute)
    if x >= y:
        p += PENALTY_RATIO * (x - y + 1)
    if x < 0:
        p += PENALTY_RATIO * (-x)
    if y < 0:
        p += PENALTY_RATIO * (-y)
    return p

def fitness(x, y):
    return objective(x, y) + penalty(x, y)

# --- Initial Solution ---
def greedy_initial_solution():
    # Start with y = 1, find minimal x such that constraints are met
    best_x, best_y = None, None
    best_val = float('inf')
    for y in range(1, 100):  # Increased upper limit for feasibility
        for x in range(0, y):
            if constraint_nonneg(x, y):
                if constraint_slices(x, y) and constraint_grease(x, y) and constraint_ratio(x, y):
                    val = objective(x, y)
                    if val < best_val:
                        best_x, best_y = x, y
                        best_val = val
    if best_x is not None:
        return (best_x, best_y)
    # Otherwise, return a feasible solution with penalty
    return (0, 1)

# --- Low-level Heuristic Operators ---
def operator_greedy_construct(sol):
    # Try to construct a feasible solution greedily
    # Increase y until grease constraint, then increase x until slice constraint
    x, y = sol
    y = max(1, y)
    x = max(0, x)
    # First, try to satisfy grease constraint by increasing y
    while 3*x + 6*y > maximum_grease_per_minute:
        if y > 1:
            y -= 1
        else:
            break
    # Then, try to satisfy slices constraint by increasing x or y
    while 5*x + 8*y < minimum_slices_per_minute:
        # Try increasing y if possible
        if 3*x + 6*(y+1) <= maximum_grease_per_minute and x < y+1:
            y += 1
        elif 3*(x+1) + 6*y <= maximum_grease_per_minute and (x+1) < y:
            x += 1
        else:
            break
    # Enforce ratio constraint
    if x >= y:
        y = x + 1
    return (x, y)

def operator_local_search_swap(sol):
    # Try swap: decrease y, increase x, or vice versa (keeping constraints)
    x, y = sol
    candidates = []
    # Swap: try increasing x by 1, decreasing y by 1
    if y > 1:
        new_x, new_y = x+1, y-1
        if constraint_nonneg(new_x, new_y):
            candidates.append((new_x, new_y))
    # Swap: try decreasing x by 1, increasing y by 1
    if x > 0:
        new_x, new_y = x-1, y+1
        if constraint_nonneg(new_x, new_y):
            candidates.append((new_x, new_y))
    # Try moving both up/down
    if x > 0 and y > 1:
        candidates.append((x-1, y-1))
    candidates.append((x+1, y+1))
    # Select best feasible or least penalty
    best = sol
    best_fit = fitness(*sol)
    for cand in candidates:
        fit = fitness(*cand)
        if fit < best_fit:
            best = cand
            best_fit = fit
    return best

def operator_perturbation(sol):
    # Randomly perturb x and y within small range
    x, y = sol
    for _ in range(3):
        dx = np.random.randint(-2, 3)
        dy = np.random.randint(-2, 3)
        nx = max(0, x + dx)
        ny = max(1, y + dy)
        if nx < ny:
            return (nx, ny)
    return sol

def operator_repair(sol):
    # Try to repair infeasible solution by fixing constraints
    x, y = sol
    x = max(0, x)
    y = max(1, y)
    # Enforce x < y
    if x >= y:
        y = x + 1
    # Enforce grease constraint
    while 3*x + 6*y > maximum_grease_per_minute and y > 1:
        y -= 1
        if x >= y:
            x = y - 1
    while 3*x + 6*y > maximum_grease_per_minute and x > 0:
        x -= 1
    # Enforce slices constraint
    while 5*x + 8*y < minimum_slices_per_minute:
        if 3*(x+1) + 6*y <= maximum_grease_per_minute and (x+1) < y:
            x += 1
        elif 3*x + 6*(y+1) <= maximum_grease_per_minute:
            y += 1
        else:
            break
    # Enforce x < y
    if x >= y:
        y = x + 1
    return (x, y)

# --- Hyper-Heuristic Selection Mechanism ---
# Reinforcement-learning style: reward operator if it improves solution, else penalize.
class HyperHeuristicSelector:
    def __init__(self, operators):
        self.operators = operators
        self.n_ops = len(operators)
        self.weights = np.ones(self.n_ops)
        self.epsilon = 0.1  # Exploration probability

    def select_operator(self):
        if np.random.rand() < self.epsilon:
            # Explore: random operator
            idx = np.random.randint(self.n_ops)
        else:
            # Exploit: weighted random
            prob = self.weights / self.weights.sum()
            idx = np.random.choice(self.n_ops, p=prob)
        return idx, self.operators[idx]

    def update(self, idx, improvement):
        # improvement > 0: reward, improvement <= 0: penalize
        if improvement > 0:
            self.weights[idx] += 2 * improvement
        else:
            self.weights[idx] *= 0.95  # Slight penalty

# --- Main Hyper-heuristic Search Loop ---
def solve(num_iter=200):
    operators = [
        operator_greedy_construct,
        operator_local_search_swap,
        operator_perturbation,
        operator_repair
    ]
    selector = HyperHeuristicSelector(operators)

    current = greedy_initial_solution()
    best = current
    best_fit = fitness(*best)
    history = [best_fit]

    for it in range(num_iter):
        idx, op = selector.select_operator()
        candidate = op(current)
        # Always repair candidate (to help feasibility)
        candidate = operator_repair(candidate)
        cand_fit = fitness(*candidate)
        improvement = best_fit - cand_fit
        selector.update(idx, improvement)
        # Accept if candidate is better
        if cand_fit < best_fit:
            best = candidate
            best_fit = cand_fit
            current = candidate
        else:
            # Accept with probability
            if np.random.rand() < 0.1:
                current = candidate
        history.append(best_fit)

    # Final repair to ensure feasibility
    best = operator_repair(best)
    best_fit = fitness(*best)
    # If still infeasible, brute-force search in small domain
    if penalty(*best) > 0:
        # Try all x in [0,100], y in [1,100] with x < y
        min_fit = float('inf')
        min_sol = None
        for y in range(1, 101):
            for x in range(0, y):
                if constraint_nonneg(x, y) and constraint_slices(x, y) and constraint_grease(x, y) and constraint_ratio(x, y):
                    fit = objective(x, y)
                    if fit < min_fit:
                        min_fit = fit
                        min_sol = (x, y)
        if min_sol is not None:
            best = min_sol
            best_fit = min_fit
        else:
            # If no feasible solution found, set to a default infeasible value
            best_fit = float('inf')

    return best, best_fit

if __name__ == "__main__":
    np.random.seed(42)
    best_sol, best_obj = solve(num_iter=200)
    print(f"OBJECTIVE_VALUE: {best_obj}")
